INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('496', '<p><strong>91. จากข้อความต่อไปนี้ ข้อใดเรียงลำดับได้ถูกต้อง</strong></p><p>1) ไทยส่งออกผลิตภัณฑ์มันสำปะหลังเป็นอันดับ 1 ของโลกมายาวนาน<br/>2) ประเทศไทยมีพื้นที่ปลูกมันสำปะหลังเป็นอันดับ 3 ของโลก<br/>3) สามารถสร้างรายได้เข้าประเทศปีละกว่า 3 หมื่นล้านบาท<br/>4) มันสำปะหลังปลูกมากที่สุดในภาคตะวันออกเฉียงเหนือ</p>', '{"A":"2 - 4 - 1 - 3","B":"4 - 3 - 2 - 1","C":"1 - 2 - 4 - 1","D":"2 - 3 - 4 - 1"}', 'A', '<p><strong>ตอบ 1) 2 - 4 - 1 - 3</strong></p><p>เรียบเรียงเป็นบทความได้ ดังนี้<br/>ประเทศไทยมีพื้นที่ปลูกมันสำปะหลังเป็นอันดับ 3 ของโลก (2)<br/>มันสำปะหลังปลูกมากที่สุดในภาคตะวันออกเฉียงเหนือ (4)<br/>ไทยส่งออกผลิตภัณฑ์มันสำปะหลังเป็นอันดับ 1 ของโลกมายาวนาน (1)<br/>สามารถสร้างรายได้เข้าประเทศปีละกว่า 3 หมื่นล้านบาท (3)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เรียงประโยค"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('497', '<p><strong>92. จากข้อความต่อไปนี้ ข้อใดเรียงลำดับได้ถูกต้อง</strong></p><p>1) ในที่สุดก็พบว่า สุนัขมีประโยชน์ในการปราบฮอกวีดดีที่สุด เพราะมันสามารถค้นหาและขุดรากทิ้งได้ทั้งหมด<br/>2) รัฐบาลต้องสูญเสียค่าพ่นยากำจัดวัชพืชเป็นจำนวนมหาศาล กระนั้นมันก็สามารถอยู่รอดและงอกใหม่ได้อีก<br/>3) ออสเตรเลียประสบปัญหาการรุกรานของวัชพืชโดยเฉพาะฮอกวีด ที่มาแย่งอาหารจากพืชเศรษฐกิจที่ปลูก<br/>4) แต่สิ่งที่ไม่ง่าย คือ ต้องการเร่งฝึกสุนัข โดยเฉพาะสายพันธุ์ค็อกเกอร์สเปเนียล ซึ่งมีจมูกที่ไวเป็นเลิศ</p>', '{"A":"3 - 1 - 4 - 2","B":"1 - 4 - 3 - 2","C":"2 - 1 - 4 - 3","D":"3 - 2 - 1 - 4"}', 'D', '<p><strong>ตอบ 4) 3 - 2 - 1 - 4</strong></p><p>เรียบเรียงเป็นบทความได้ ดังนี้<br/>ออสเตรเลียประสบปัญหาการรุกรานของวัชพืชโดยเฉพาะฮอกวีด ที่มาแย่งอาหารจากพืชเศรษฐกิจที่ปลูก (3)<br/>รัฐบาลต้องสูญเสียค่าพ่นยากำจัดวัชพืชเป็นจำนวนมหาศาล กระนั้นมันก็สามารถอยู่รอดและงอกใหม่ได้อีก (2)<br/>ในที่สุดก็พบว่า สุนัขมีประโยชน์ในการปราบฮอกวีดดีที่สุด เพราะมันสามารถค้นหาและขุดรากทิ้งได้ทั้งหมด (1)<br/>แต่สิ่งที่ไม่ง่าย คือ ต้องการเร่งฝึกสุนัข โดยเฉพาะสายพันธุ์ค็อกเกอร์สเปเนียล ซึ่งมีจมูกที่ไวเป็นเลิศ (4)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เรียงประโยค"]', '2559');
